'use client';
// src/components/ServicePortal.jsx
import React from 'react';
import { NLI_LANGUAGES } from '../data/nliRules';

const ENGLISH_SERVICES = {
  flight: { icon: '✈️', title: 'Flight Status', desc: 'Check real-time departures, arrivals, and gate details.' },
  map:    { icon: '🗺️', title: 'Terminal Map', desc: 'Navigate terminals, shops, lounges, and boarding gates.' },
  ticket: { icon: '🎟️', title: 'Ticket Purchase', desc: 'Buy or print transit cards for trains, shuttles, or connection flights.' },
  support:{ icon: '🤖', title: 'Helpdesk & Chatbot', desc: 'Talk with our automated support desk for direct answers.' },
};

function getPortalData(langCode) {
  if (!langCode || langCode === 'en' || langCode === 'en-PH') {
    return {
      brand: langCode === 'en-PH' ? 'Smart Kiosk (Philippines)' : 'Smart Kiosk Terminal',
      welcomeTitle: 'Airport Self-Service Portal',
      welcomeSub: 'Select a service below to proceed.',
      pillFlag: langCode === 'en-PH' ? '🇵🇭' : '🇬🇧',
      pillText: langCode === 'en-PH' ? 'English (PH)' : 'English',
      footerHelp: 'Need physical assistance? Terminal agents are on standby.',
      btnReset: 'End Session / Reset',
      services: ENGLISH_SERVICES,
    };
  }

  // Cebuano
  if (langCode === 'ceb') {
    return {
      brand: 'Smart Kiosk (Bisaya)', pillFlag: '🇵🇭', pillText: 'Cebuano',
      welcomeTitle: 'Maayong pag-abot sa Airport Service Portal!',
      welcomeSub: 'Pilia ang serbisyo sa ubos o pagsulti para sa tabang.',
      footerHelp: '🙋: Need physical assistance? Terminal agents are on standby.',
      btnReset: 'Tapuson / I-reset',
      services: {
        flight: { icon: '✈️', title: 'Katayuan sa Flight', desc: 'Susiha ang real-time nga paglarga, pag-abot, ug mga detalye sa gate.' },
        map:    { icon: '🗺️', title: 'Mapa sa Terminal', desc: 'Pag-navigate sa mga terminal, tindahan, lounges, ug boarding gates.' },
        ticket: { icon: '🎟️', title: 'Pagpalit og Tiket', desc: 'Pagpalit o pag-print og mga tiket para sa tren, bus, o nagkonektang flight.' },
        support:{ icon: '🤖', title: 'Suporta ug Chatbot', desc: 'Pakigsulti sa among virtual assistant para sa dali nga tubag.' },
      }
    };
  }

  // Malay
  if (langCode === 'ms') {
    return {
      brand: 'Portal Kios Pintar', pillFlag: '🇲🇾', pillText: 'Bahasa Melayu',
      welcomeTitle: 'Selamat Datang ke Portal Perkhidmatan Lapangan Terbang!',
      welcomeSub: 'Pilih perkhidmatan di bawah atau bercakap untuk mendapatkan bantuan.',
      footerHelp: '🙋: Need physical assistance? Terminal agents are on standby.',
      btnReset: 'Tamat / Set Semula',
      services: {
        flight: { icon: '✈️', title: 'Status Penerbangan', desc: 'Semak waktu berlepas, ketibaan dan butiran pintu secara langsung.' },
        map:    { icon: '🗺️', title: 'Peta Terminal', desc: 'Cari jalan di terminal, kedai, ruang rehat dan pintu berlepas.' },
        ticket: { icon: '🎟️', title: 'Pembelian Tiket', desc: 'Beli atau cetak tiket tren transit, bas shuttle atau penerbangan sambungan.' },
        support:{ icon: '🤖', title: 'Sokongan & Chatbot', desc: 'Bercakap dengan pembantu maya kami untuk jawapan pantas.' },
      }
    };
  }

  // Base NLI languages
  const base = langCode.split('-')[0];
  const lang = NLI_LANGUAGES.find(l => l.code === base);
  if (!lang) return getPortalData('en');

  return {
    brand: `Smart Kiosk (${lang.nativeName})`,
    pillFlag: lang.flag, pillText: lang.nativeName,
    welcomeTitle: lang.welcomeMessage,
    welcomeSub: lang.welcomeSubtitle,
    footerHelp: `Physical help? / 🙋: Terminal agents are on standby.`,
    btnReset: 'End / Reset',
    services: {
      flight: { icon: '✈️', title: lang.services.flight.title, desc: lang.services.flight.desc },
      map:    { icon: '🗺️', title: lang.services.map.title, desc: lang.services.map.desc },
      ticket: { icon: '🎟️', title: lang.services.ticket.title, desc: lang.services.ticket.desc },
      support:{ icon: '🤖', title: lang.services.support.title, desc: lang.services.support.desc },
    }
  };
}

export default function ServicePortal({ langCode, onOpenModal, onReset, onToggleLang, detectedLanguage }) {
  const data = getPortalData(langCode);

  return (
    <div className="kiosk-screen active" id="screenPortal">
      <div className="portal-layout">
        <div className="portal-top-bar">
          <div className="portal-welcome-msg">
            <h2 className="portal-welcome-title">{data.welcomeTitle}</h2>
            <p className="portal-welcome-sub">{data.welcomeSub}</p>
          </div>
          <div className="language-switch-pill" title="Change Language" onClick={onToggleLang} style={{ cursor: 'pointer' }}>
            <span className="pill-flag">{data.pillFlag}</span>
            <span className="pill-text">{data.pillText}</span>
          </div>
        </div>

        <div className="services-grid">
          {Object.entries(data.services).map(([key, svc]) => (
            <div key={key} className="service-card" id={`card-${key}`} onClick={() => onOpenModal(key)}>
              <div className="service-icon-box">{svc.icon}</div>
              <div className="service-info">
                <h3 className="service-title">{svc.title}</h3>
                <p className="service-desc">{svc.desc}</p>
              </div>
            </div>
          ))}
        </div>

        <footer className="portal-footer">
          <div className="kiosk-help-text">
            <span className="kiosk-help-pulse" />
            <span>{data.footerHelp}</span>
          </div>
          <button className="btn-reset" onClick={onReset}>{data.btnReset}</button>
        </footer>
      </div>
    </div>
  );
}

export { getPortalData };
